import { companies, services, dialogs, staticCategories } from "/src/data.js";

// Init State in LocalStorage if not present
if (!localStorage.getItem('promzona_state')) {
  localStorage.setItem('promzona_state', JSON.stringify({
    localAds: services,
    chatDialogs: dialogs,
    searchQueryGlobal: '',
    activeLetter: 'Все',
    activeDialogId: 'nordic'
  }));
}

export function getPromzonaState() {
  return JSON.parse(localStorage.getItem('promzona_state'));
}

export function savePromzonaState(state) {
  localStorage.setItem('promzona_state', JSON.stringify(state));
}

// Redirect and trigger chat
export function startInstantChat(id, name, avatar) {
  const state = getPromzonaState();
  const dialogExists = state.chatDialogs.find(d => d.id === id);
  
  if (!dialogExists) {
    state.chatDialogs.unshift({
      id: id,
      name: name,
      avatar: avatar,
      lastMessageText: 'Здравствуйте! Мы готовы принять ваш чертеж.',
      lastMessageTime: 'Только что',
      unread: false,
      type: 'orders',
      messages: [
        { id: '1', text: 'Здравствуйте! Да, мы готовы обсудить технические требования к партии. Какой объем планируется?', timestamp: 'Только что', sender: 'them' }
      ]
    });
  }
  
  state.activeDialogId = id;
  savePromzonaState(state);
  window.location.href = `messages.html`;
}

// Delete and refresh
export function deleteAd(id) {
  const state = getPromzonaState();
  state.localAds = state.localAds.filter(ad => ad.id !== id);
  savePromzonaState(state);
  window.location.reload();
}

