// Multi-file ZIP download system
export async function downloadProjectAsZip() {
  const btn = document.getElementById('zip-download-btn');
  const originalText = btn ? btn.innerHTML : '';
  if (btn) {
    btn.disabled = true;
    btn.innerHTML = '<span class="animate-spin mr-1">⌛</span> Сборка HTML...';
  }

  try {
    if (typeof JSZip === 'undefined') {
      throw new Error('JSZip библиотека не загрузилась. Пожалуйста, убедитесь, что есть интернет-соединение.');
    }
    const zip = new JSZip();

    // List of all HTML pages we created
    const pages = [
      'index.html',
      'catalog.html',
      'production.html',
      'services.html',
      'construction.html',
      'companies.html',
      'service-detail.html',
      'company-detail.html',
      'dashboard.html',
      'messages.html',
      'create-ad.html'
    ];

    // Download each page asynchronously
    for (const page of pages) {
      try {
        const res = await fetch(`/${page}`);
        if (res.ok) {
          const text = await res.text();
          zip.file(page, text);
        }
      } catch (pageErr) {
        console.warn(`Could not include ${page} in zip package:`, pageErr);
      }
    }

    // Include javascript assets
    try {
      const dataRes = await fetch('/src/data.js');
      const dataText = await dataRes.text();
      zip.file('src/data.js', dataText);
    } catch {}

    try {
      const commonRes = await fetch('/src/common.js');
      const commonText = await commonRes.text();
      zip.file('src/common.js', commonText);
    } catch {}

    // Add README.md
    zip.file("README.md", `# PromZona B2B — Федеральный реестр промышленности

Данный архив содержит полностью рабочий, автономный мультистраничный проект!

## Особенности архитектуры:
1. **Чистый HTML5 & Vanilla JS & Tailwind CSS** — весь проект собран в виде отдельных HTML файлов.
2. **Нулевой порог запуска** — нет сложных сборщиков, TypeScript, или Vite конфигов для локальной работы.
3. **Локальный роутинг** — переходы между страницами осуществляются по классическим ссылкам (например, \`catalog.html\`).
4. **Сохранение состояния** — добавление объявлений, диалоги в чате, фильтры синхронизируются через \`localStorage\` браузера!

## Как запустить:
1. Распакуйте архив.
2. Запустите проект через локальный веб-сервер. Например в VS Code:
   - Установите расширение **Live Server** и нажмите **Go Live**.
   - Либо из консоли в папке проекта:
     \`\`\`bash
     npx serve
     \`\`\`
     или
     \`\`\`bash
     python -m http.server 8000
     \`\`\`
3. Откройте адрес сервера в любом браузере и наслаждайтесь!
`);

    // Compile zip
    const blob = await zip.generateAsync({ type: "blob" });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = "promzona_b2b_multi_page.zip";
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

    if (btn) {
      btn.innerHTML = '✅ Проект скачан!';
      setTimeout(() => {
        btn.disabled = false;
        btn.innerHTML = originalText;
        if (window.lucide) window.lucide.createIcons();
      }, 3000);
    }

  } catch (err) {
    console.error("ZIP Generation Failed:", err);
    alert("Ошибка сборки ZIP: " + err.message);
    if (btn) {
      btn.disabled = false;
      btn.innerHTML = originalText;
      if (window.lucide) window.lucide.createIcons();
    }
  }
}

